import { workflow, step } from "@executioncontextprotocol/core"

export default workflow("Validate then echo")
  .run([
    step("@executioncontextprotocol/demo.validate", "Validate").id("validate").with({ payload: { ok: true } }).as("validated"),
    step("@executioncontextprotocol/demo.echo", "Echo").id("echo").with({ value: "hello" }).as("echo"),
  ])

import { workflow, step } from "@executioncontextprotocol/core"

export default workflow("Echo translate")
  .run([
    step("@executioncontextprotocol/demo.echo", "Echo").id("echo").with({ value: "hello" }).as("echo"),
    step("@executioncontextprotocol/demo.translate", "Translate").id("translate").with({ text: "hello", targetLang: "es" }).as("translated"),
